// GLS Atlas — login único + GetSummarySheets (DealerCode<9000) + ExportDeliverySheet → fallback GetDeliveryItems
let XLSX = null;
try { XLSX = require('xlsx'); } catch(e) {}

const BASE     = 'https://atlas.gls-spain.es';
const GLS_USER = $env.GLS_USER || '';
const GLS_PASS = $env.GLS_PASS || '';

const CP_MAP = {
  '10130':'CARMEN MATEOS','10135':'CARMEN MATEOS','10134':'CARMEN MATEOS','10109':'CARMEN MATEOS','10110':'CARMEN MATEOS','10262':'CARMEN MATEOS',
  '10132':'CARLOS AVIS','10184':'CARLOS AVIS','10186':'CARLOS AVIS','10180':'CARLOS AVIS','10170':'CARLOS AVIS','10161':'CARLOS AVIS','10187':'CARLOS AVIS',
  '10140':'ANA ISABEL','10160':'RUBEN NEVADO','10198':'JUAN PEDRO',
  '10136':'JORGE JUAN','10129':'JORGE JUAN','10374':'JORGE JUAN','10379':'JORGE JUAN','10137':'JORGE JUAN',
  '10200':'CHRISTIAN RUBIO','10290':'CHRISTIAN RUBIO','10291':'CHRISTIAN RUBIO','10252':'CHRISTIAN RUBIO',
  '10251':'ALVARO MUÑOZ',
  '10210':'SERGIO CATALAN','10269':'SERGIO CATALAN','10230':'SERGIO CATALAN','10240':'SERGIO CATALAN','10250':'SERGIO CATALAN','10261':'SERGIO CATALAN','10260':'SERGIO CATALAN','10189':'SERGIO CATALAN','10280':'SERGIO CATALAN','10271':'SERGIO CATALAN',
  '10100':'JUAN GOMEZ','10191':'JUAN GOMEZ','10183':'JUAN GOMEZ',
};
const assignDriver = cp => CP_MAP[String(cp || '').trim()] || null;

const jar = {};
function saveCookies(resHeaders) {
  let cookies = [];
  try { cookies = resHeaders.getSetCookie ? resHeaders.getSetCookie() : []; } catch(e) {}
  if (!cookies.length) { const h = resHeaders.get('set-cookie'); if (h) cookies = [h]; }
  for (const c of cookies) {
    const pair = c.split(';')[0].trim();
    const eq = pair.indexOf('=');
    if (eq > 0) jar[pair.substring(0, eq).trim()] = pair;
  }
}
function cookieHeader() { return Object.values(jar).join('; '); }

async function req(method, url, opts, depth) {
  depth = depth || 0;
  if (depth > 12) throw new Error('Demasiadas redirecciones');
  const extra = opts || {};
  const binary = !!extra.binary;
  const headers = Object.assign({ 'User-Agent': 'Mozilla/5.0' }, extra.h || {});
  const ck = cookieHeader();
  if (ck) headers['Cookie'] = ck;
  const res = await fetch(url, { method, headers, body: extra.body || undefined, redirect: 'manual' });
  saveCookies(res.headers);
  if ([301,302,303,307,308].includes(res.status)) {
    const loc = res.headers.get('location') || '';
    const next = loc.startsWith('http') ? loc : BASE + loc;
    return req([301,302,303].includes(res.status) ? 'GET' : method, next, { h: extra.h || {}, binary }, depth + 1);
  }
  if (binary) {
    const ct = res.headers.get('content-type') || '';
    const data = Buffer.from(await res.arrayBuffer());
    return { status: res.status, ct, data };
  }
  const text = await res.text();
  return { status: res.status, body: text };
}

function csrf(html) {
  const m = html.match(/name="__RequestVerificationToken"[^>]*value="([^"]+)"/);
  if (!m) throw new Error('Token CSRF no encontrado');
  return m[1];
}

const hoy = new Date();
const fmt = d => String(d.getDate()).padStart(2,'0') + '/' + String(d.getMonth()+1).padStart(2,'0') + '/' + d.getFullYear();
const hoyStr = fmt(hoy);
const desde = hoyStr;
const hasta  = hoyStr;

// 1. Login
const rLogin = await req('GET', BASE + '/Account/Login');
const csrf1 = csrf(rLogin.body);
const rPost = await req('POST', BASE + '/Account/Login', {
  h: { 'Content-Type': 'application/x-www-form-urlencoded', 'Referer': BASE + '/Account/Login' },
  body: 'Username=' + encodeURIComponent(GLS_USER) + '&Password=' + encodeURIComponent(GLS_PASS) + '&__RequestVerificationToken=' + encodeURIComponent(csrf1)
});
if (rPost.body.toLowerCase().includes('name="password"'))
  throw new Error('Login fallido — revisa GLS_USER y GLS_PASS en n8n');

// 2. CSRF para POST
const rIdx = await req('GET', BASE + '/delivery/index');
if (rIdx.body.toLowerCase().includes('<title>sign in')) throw new Error('Sesión inválida tras login');
const csrf2 = csrf(rIdx.body);

const postH = {
  'Content-Type': 'application/x-www-form-urlencoded',
  'X-Requested-With': 'XMLHttpRequest',
  'Accept': 'application/json, text/javascript, */*; q=0.01',
  'Referer': BASE + '/delivery/index'
};
const tokenParam = '__RequestVerificationToken=' + encodeURIComponent(csrf2);
const dateParams = '&filters%5Bsince%5D=' + encodeURIComponent(desde) + '&filters%5Buntil%5D=' + encodeURIComponent(hasta);

// 3. Hojas del mes — solo hojas de repartidor (DealerCode < 9000)
const rSheets = await req('POST', BASE + '/delivery/GetSummarySheets', { h: postH, body: tokenParam + dateParams });
let sheetsRaw = rSheets.body;
let sheetsBodyStr = String(sheetsRaw || '').substring(0, 800);
try { sheetsRaw = JSON.parse(sheetsRaw); } catch(e) {}

const allList = (sheetsRaw && sheetsRaw.Data && sheetsRaw.Data.List) || [];
const hojas = allList.filter(s => s.SheetCode != null && s.DealerCode && s.DealerCode < 9000);

if (!hojas.length) return [{ json: {
  envios: [], hojas: 0,
  errores: ['Sin hojas de repartidor (DealerCode<9000). Revisa si hay rutas asignadas hoy.'],
  _debug: {
    sheetsStatus: rSheets.status,
    totalEnLista: allList.length,
    todosLosCodigos: allList.map(s => ({ SheetCode: s.SheetCode, DealerCode: s.DealerCode, Dealer: s.Dealer })),
    sheetsBody: sheetsBodyStr
  }
} }];

const SRV = {
  '0':{'label':'10 HORAS','color':'#f59e0b','premium':true},
  '2':{'label':'VALIJA','color':'#f97316','premium':true},
  '92':{'label':'PARCEL','color':'#3b82f6','premium':false},
  '10':{'label':'RETORNO','color':'#f97316','premium':false},
  '37':{'label':'ECONOMY','color':'#94a3b8','premium':false},
  '96':{'label':'24 HORAS','color':'#10b981','premium':true},
  '97':{'label':'PARCEL','color':'#3b82f6','premium':false},
  '98':{'label':'ENTREGA HOY','color':'#10b981','premium':true},
  '1':{'label':'19 HORAS','color':'#6366f1','premium':false},
};
function srv(code) { return SRV[String(code)] || { label: String(code)||'STD', color:'#64748b', premium:false }; }

const envios = [];
const errores = [];

for (const hoja of hojas) {
  const sheetP = '&sheetCode=' + encodeURIComponent(String(hoja.SheetCode)) +
                 '&placeCode='  + encodeURIComponent(String(hoja.PlaceCode || ''));
  const dealerFallback = hoja.Dealer || hoja.dealer || 'SIN ASIGNAR ⚠';
  let ok = false;

  // PRIMARIO: ExportDeliverySheet (Excel)
  if (XLSX) {
    try {
      const rXls = await req('POST', BASE + '/delivery/ExportDeliverySheet',
        { h: { ...postH, 'Accept': '*/*' }, body: tokenParam + sheetP + dateParams, binary: true });
      const ct = (rXls.ct || '').toLowerCase();
      const isXls = ct.includes('spreadsheet') || ct.includes('excel') || ct.includes('openxmlformats') || ct.includes('octet-stream');
      if (rXls.status === 200 && isXls && rXls.data && rXls.data.length > 100) {
        const wb = XLSX.read(rXls.data, { type: 'buffer' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const rows = XLSX.utils.sheet_to_json(ws, { defval: '' });
        for (const row of rows) {
          const k = {};
          for (const key of Object.keys(row)) {
            const norm = key.toLowerCase().replace(/\s+/g,'').normalize('NFD').replace(/[\u0300-\u036f]/g,'');
            k[norm] = row[key];
          }
          const id = String(k['codexp'] || k['codigoenvio'] || k['nenvio'] || '').trim();
          if (!id) continue;
          const cp = String(k['cp'] || k['codigopostal'] || String(hoja.PlaceCode || '') || '');
          const srvCode = String(k['servicio'] || k['codservicio'] || k['tiposervicio'] || '96');
          const s = srv(srvCode);
          const nota = String(k['nota'] || k['observaciones'] || k['observ'] || '');
          envios.push({
            id,
            conductor: assignDriver(cp) || dealerFallback,
            cliente:   String(k['destinatario'] || k['cliente'] || ''),
            direccion: String(k['direccion']    || k['domicilio'] || ''),
            localidad: String(k['localidad']    || k['poblacion'] || ''),
            cp, estado: parseInt(k['estado'] || k['eventococigo'] || 6) || 6,
            bultos: parseInt(k['bultos'] || 1) || 1,
            kgs:    parseFloat(k['kgs'] || k['peso'] || 0) || 0,
            fPrevista: String(k['fprevista'] || k['fechaprevista'] || hoyStr),
            srvCode, srvLabel: s.label, srvColor: s.color, isPremium: s.premium,
            nota, tieneNota: nota.length > 2
          });
        }
        ok = true;
      } else {
        errores.push({ sheetCode: hoja.SheetCode, dealer: dealerFallback, info: 'Excel: HTTP ' + rXls.status + ' ct=' + rXls.ct });
      }
    } catch(e) {
      errores.push({ sheetCode: hoja.SheetCode, dealer: dealerFallback, info: 'Excel error: ' + e.message });
    }
  }

  // FALLBACK: GetDeliveryItems JSON
  if (!ok) {
    try {
      const rJ = await req('POST', BASE + '/delivery/GetDeliveryItems',
        { h: { ...postH }, body: tokenParam + sheetP + dateParams });
      let jr = rJ.body;
      try { jr = JSON.parse(jr); } catch(e) {}
      const items = (jr && jr.Data && jr.Data.List) || (Array.isArray(jr) ? jr : []);
      if (items.length > 0) {
        for (const i of items) {
          const id = String(i.CodExp || i.codexp || i.Id || '').trim();
          if (!id) continue;
          const cp = String(i.CP || i.Cp || i.cp || String(hoja.PlaceCode || '') || '');
          const srvCode = String(i.CodServicio || i.codservicio || i.ServCode || '96');
          const s = srv(srvCode);
          const nota = String(i.Observ || i.observ || i.Nota || '');
          envios.push({
            id,
            conductor: assignDriver(cp) || dealerFallback,
            cliente:   String(i.Destinatario || i.destinatario || ''),
            direccion: String(i.Direccion    || i.direccion    || ''),
            localidad: String(i.Localidad    || i.localidad    || ''),
            cp, estado: parseInt(i.EventoCodigo || i.eventoCodigo || 6) || 6,
            bultos: parseInt(i.Bultos || i.bultos || 1) || 1,
            kgs:    parseFloat(i.Kgs   || i.kgs   || 0) || 0,
            fPrevista: String(i.FPreviEntrega || i.fPreviEntrega || hoyStr),
            srvCode, srvLabel: s.label, srvColor: s.color, isPremium: s.premium,
            nota, tieneNota: nota.length > 2
          });
        }
        ok = true;
      } else {
        errores.push({ sheetCode: hoja.SheetCode, dealer: dealerFallback, info: 'GetDeliveryItems: 0 items (HTTP ' + rJ.status + ')', body: String(rJ.body || '').substring(0, 300) });
      }
    } catch(e) {
      errores.push({ sheetCode: hoja.SheetCode, dealer: dealerFallback, error: 'GetDeliveryItems: ' + e.message });
    }
  }
}

return [{ json: {
  envios,
  hojas: hojas.length,
  errores,
  _debug: { total: envios.length, hojas: hojas.length, xlsxAvailable: !!XLSX, desde, hasta }
} }];

