const items = (raw && raw.Data && raw.Data.List) || (Array.isArray(raw) ? raw : []);
const updates = items
  .map(i => ({ codexp: String(i.CodExp || i.codexp || i.Id || ''), eventoCodigo: String(i.EventoCodigo || i.eventoCodigo || 6) }))
  .filter(i => i.codexp);

return updates.length ? updates.map(u => ({ json: u })) : [{ json: { codexp: '', eventoCodigo: '0' } }];
